package main

import (
    "encoding/json"
    "fmt"
    "log"
    "net/http"
    "strconv"
    "sync"
    "testing"
)

// ---- Models ----
type Task struct {
    ID          int    `json:"id"`
    Title       string `json:"title"`
    Description string `json:"description"`
    Status      string `json:"status"`
}

// ---- In-memory repository ----
type TaskRepo struct {
    mu    sync.Mutex
    tasks []Task
    nextID int
}

func NewTaskRepo() *TaskRepo {
    return &TaskRepo{
        tasks:  []Task{},
        nextID: 1,
    }
}

func (r *TaskRepo) Create(title, description, status string) Task {
    r.mu.Lock()
    defer r.mu.Unlock()

    task := Task{
        ID:          r.nextID,
        Title:       title,
        Description: description,
        Status:      status,
    }
    r.nextID++
    r.tasks = append(r.tasks, task)
    return task
}

func (r *TaskRepo) GetAll() []Task {
    r.mu.Lock()
    defer r.mu.Unlock()
    return r.tasks
}

func (r *TaskRepo) GetByID(id int) (Task, bool) {
    r.mu.Lock()
    defer r.mu.Unlock()

    for _, task := range r.tasks {
        if task.ID == id {
            return task, true
        }
    }
    return Task{}, false
}

func (r *TaskRepo) Update(id int, title, description, status string) (Task, bool) {
    r.mu.Lock()
    defer r.mu.Unlock()

    for i, task := range r.tasks {
        if task.ID == id {
            task.Title = title
            task.Description = description
            task.Status = status
            r.tasks[i] = task
            return task, true
        }
    }
    return Task{}, false
}

func (r *TaskRepo) Delete(id int) bool {
    r.mu.Lock()
    defer r.mu.Unlock()

    for i, task := range r.tasks {
        if task.ID == id {
            r.tasks = append(r.tasks[:i], r.tasks[i+1:]...)
            return true
        }
    }
    return false
}

// ---- Handlers ----
type TaskHandler struct {
    repo *TaskRepo
}

func NewTaskHandler(repo *TaskRepo) *TaskHandler {
    return &TaskHandler{repo: repo}
}

func (h *TaskHandler) GetTasks(w http.ResponseWriter, r *http.Request) {
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(h.repo.GetAll())
}

func (h *TaskHandler) CreateTask(w http.ResponseWriter, r *http.Request) {
    var task Task
    if err := json.NewDecoder(r.Body).Decode(&task); err != nil {
        w.WriteHeader(http.StatusBadRequest)
        json.NewEncoder(w).Encode(map[string]string{"error": "invalid request"})
        return
    }

    created := h.repo.Create(task.Title, task.Description, task.Status)
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(http.StatusCreated)
    json.NewEncoder(w).Encode(created)
}

func (h *TaskHandler) DeleteTask(w http.ResponseWriter, r *http.Request) {
    // Simplified for demonstration
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(map[string]string{"message": "deleted"})
}

// ---- Tests ----
func TestTaskRepo(t *testing.T) {
    repo := NewTaskRepo()

    // Test Create
    task := repo.Create("Test Task", "Description", "pending")
    if task.ID != 1 {
        t.Errorf("Expected ID 1, got %d", task.ID)
    }
    if task.Title != "Test Task" {
        t.Errorf("Expected title 'Test Task', got %s", task.Title)
    }

    // Test GetAll
    tasks := repo.GetAll()
    if len(tasks) != 1 {
        t.Errorf("Expected 1 task, got %d", len(tasks))
    }

    // Test GetByID
    found, ok := repo.GetByID(1)
    if !ok {
        t.Error("Expected task with ID 1 to exist")
    }
    if found.Title != "Test Task" {
        t.Errorf("Expected title 'Test Task', got %s", found.Title)
    }

    // Test Update
    updated, ok := repo.Update(1, "Updated Task", "New description", "done")
    if !ok {
        t.Error("Expected update to succeed")
    }
    if updated.Status != "done" {
        t.Errorf("Expected status 'done', got %s", updated.Status)
    }

    // Test Delete
    ok = repo.Delete(1)
    if !ok {
        t.Error("Expected delete to succeed")
    }
    tasks = repo.GetAll()
    if len(tasks) != 0 {
        t.Errorf("Expected 0 tasks, got %d", len(tasks))
    }
}

func main() {
    repo := NewTaskRepo()
    handler := NewTaskHandler(repo)

    // Seed some data
    handler.repo.Create("Learn Go", "Complete the Go tutorial", "pending")
    handler.repo.Create("Build API", "Create the REST API", "in-progress")

    fmt.Println("Server running on :8080")
    log.Fatal(http.ListenAndServe(":8080", nil))
}

