package main

import (
    "testing"
)

func TestUpdate(t *testing.T) {
    repo := NewTaskRepo()

    // Create a task
    task := repo.Create("Test", "Description", "pending")

    // Update existing task
    updated, ok := repo.Update(task.ID, "Updated Title", "Updated Desc", "done")
    if !ok {
        t.Error("Expected update to succeed")
    }
    if updated.Title != "Updated Title" {
        t.Errorf("Expected title 'Updated Title', got '%s'", updated.Title)
    }
    if updated.Description != "Updated Desc" {
        t.Errorf("Expected description 'Updated Desc', got '%s'", updated.Description)
    }
    if updated.Status != "done" {
        t.Errorf("Expected status 'done', got '%s'", updated.Status)
    }

    // Update non-existing task
    _, ok = repo.Update(999, "", "", "")
    if ok {
        t.Error("Expected update to fail for non-existing task")
    }
}
